from dataclasses import dataclass
from datetime import date
from enum import Enum


class Priority(Enum):
    P0 = "p0"   # fix before next production run of ANY experiment
    P1 = "p1"   # fix before next run of THIS experiment
    P2 = "p2"   # fix within 30 days


@dataclass
class ActionItem:
    id: str
    finding: str               # what failed
    root_cause: str            # why it failed
    fix: str                   # exact change required (file + line if possible)
    owner: str                 # GitHub handle or team
    due_date: date
    priority: Priority
    linked_experiment: str     # experiment ID this item came from
    resolved: bool = False

    def to_github_issue_body(self) -> str:
        return f"""
## Finding
{self.finding}

## Root Cause
{self.root_cause}

## Required Fix
{self.fix}

**Linked experiment:** {self.linked_experiment}
**Owner:** {self.owner}
**Due:** {self.due_date}
**Priority:** {self.priority.value.upper()}
"""

from dataclasses import dataclass
from typing import Literal


@dataclass
class ErrorBudgetEntry:
    source: Literal["incident", "chaos_experiment", "planned_maintenance"]
    id: str                        # incident ID or experiment ID
    consumed_minutes: float        # minutes of SLO budget burned
    month: str                     # YYYY-MM
    service: str


def summarize_budget(entries: list[ErrorBudgetEntry], month: str, service: str) -> dict:
    relevant = [e for e in entries if e.month == month and e.service == service]
    total = sum(e.consumed_minutes for e in relevant)
    by_source = {}
    for e in relevant:
        by_source[e.source] = by_source.get(e.source, 0) + e.consumed_minutes
    return {
        "month": month,
        "service": service,
        "total_consumed_minutes": total,
        "by_source": by_source,
    }

