import os
import yaml
from pathlib import Path


def load_registry(experiments_dir: str = "experiments") -> list[dict]:
    records = []
    for path in Path(experiments_dir).glob("*.yaml"):
        with open(path) as f:
            records.append(yaml.safe_load(f))
    return records


def coverage_summary(records: list[dict]) -> dict:
    statuses = {"confirmed": 0, "partial_failure": 0, "refuted": 0, "never_run": 0}
    stale = []
    from datetime import datetime, timezone, timedelta

    now_str = "2026-07-19"  # use args-injected date in real use
    for rec in records:
        status = rec.get("status", "never_run")
        statuses[status] = statuses.get(status, 0) + 1
        if status == "confirmed" and rec.get("last_run"):
            last_run = rec["last_run"][:10]
            # stale if last confirmed run > 90 days ago
            # (date comparison simplified for illustration)
            stale.append(rec["id"])
    return {
        "total": len(records),
        "by_status": statuses,
        "stale_candidates": stale,
        "coverage_pct": round(
            100 * statuses["confirmed"] / max(len(records), 1), 1
        ),
    }
